class UserRepository {
  constructor() {
    this.user = null;
  }

  setUser(userData) {
    if (this.user) {
      this.user = { ...this.user, ...userData };
    } else {
      this.user = userData;
    }
  }

  getUser() {
    return this.user;
  }

  clearUser() {
    this.user = null;
  }

  isLoggedIn() {
    return this.user !== null;
  }

  setFullName(fullName) {
    if (this.user) {
      this.user.fullName = fullName; // 🔥 fixed: fullName not full_name
    } else {
      this.user = { fullName }; // 🔥 fixed
    }
  }

  getFullName() {
    return this.user ? this.user.fullName : null; // 🔥 fixed
  }
}

const userRepository = new UserRepository();
export default userRepository;
